choose.when:
/* 필터 없는 경우: 서브쿼리 페이지네이션 (fast path) */ SELECT dp.data_processing_idx AS remediationId, sub.hash_id AS findNo, sub.path AS findPath, sub.regdate AS findDate, t2.TARGET_ID AS targetId, t2.NAME AS targetName, COALESCE(a.AGENT_CONNECTED_IP, tg.connected_ip) AS targetIp, s.data_type AS datatype, dp.approval_status AS approvalStatus, CASE WHEN dp.processing_flag IS NOT NULL AND dp.processing_flag != 0 THEN 'Y' ELSE 'N' END AS processYn, dp.user_no AS processUserNo, dp.regdate AS processDate, dp.notepad AS notepad, COALESCE(ptg.name, '미그룹') AS groupName FROM ( SELECT f.hash_id, f.path, f.regdate, f.target_id, f.ap_no FROM pi_find f INNER JOIN pi_targets t ON f.target_id = t.target_id AND f.ap_no = t.ap_no WHERE t.TARGET_USE = 'Y'
AND (t.NAME LIKE CONCAT('%', #{keyword}, '%') OR f.path LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY f.regdate DESC LIMIT #{offset}, #{limit} ) sub INNER JOIN pi_targets t2 ON sub.target_id = t2.target_id AND sub.ap_no = t2.ap_no LEFT JOIN pi_summary s ON sub.target_id = s.target_id AND sub.ap_no = s.ap_no AND sub.hash_id = s.object_id LEFT JOIN pi_data_processing dp ON sub.target_id = dp.target_id AND sub.ap_no = dp.ap_no AND sub.hash_id = dp.hash_id LEFT JOIN pi_agents a ON t2.NAME = a.AGENT_NAME AND t2.AP_NO = a.AP_NO AND a.AGENT_USE = 'Y' LEFT JOIN pi_target_group tg ON tg.TARGET_ID = t2.TARGET_ID AND t2.AP_NO = tg.AP_NO LEFT JOIN pi_target_group ptg ON tg.up_idx = ptg.idx
